// ============================================
// QUESTIONS BANK WITH REAL DETAILED ANSWERS
// ============================================

const questionsBank = {
  'Web Development': {
    Easy: [
      { text: "What is the difference between HTML, CSS, and JavaScript?", answer: "HTML (HyperText Markup Language) defines the structure and content of a webpage using elements like headings, paragraphs, and images. CSS (Cascading Style Sheets) controls the visual appearance — colors, fonts, layout, and spacing. JavaScript adds interactivity and behavior — like form validation, animations, and dynamic content updates. Think of HTML as the skeleton, CSS as the skin/clothes, and JavaScript as the muscles that make things move and respond." },
      { text: "What is the box model in CSS?", answer: "The CSS box model describes how every HTML element is rendered as a rectangular box with four layers: Content (the actual text or image inside), Padding (transparent space between content and border), Border (the outline around the padding), and Margin (space outside the border that separates elements from each other). By default, width and height apply only to the content area. Using box-sizing: border-box makes width and height include padding and border, which is much easier to work with in layouts." },
      { text: "What is the difference between inline and block elements in HTML?", answer: "Block elements like div, p, h1-h6, and section take up the full width available and always start on a new line. Inline elements like span, a, strong, and em only take up as much width as their content and flow within surrounding text without breaking to a new line. You can change this behavior using the CSS display property — setting display:block on a span or display:inline on a div. display:inline-block combines both — flows inline but respects width and height." },
      { text: "What is a responsive website? How do you make a website responsive?", answer: "A responsive website adapts its layout and design to look good on all screen sizes — desktop, tablet, and mobile. You achieve this using: (1) CSS Media Queries to apply different styles at different breakpoints like @media (max-width: 768px), (2) Flexible layouts with Flexbox or CSS Grid, (3) Relative units like %, em, rem, vw instead of fixed px values, (4) The viewport meta tag in the HTML head: meta name=viewport content=width=device-width initial-scale=1, and (5) Flexible images with max-width: 100% so they never overflow their container." },
      { text: "What is the difference between id and class in HTML/CSS?", answer: "An id is unique — only one element on a page should have a specific id. It is selected with # in CSS like #header and has the highest specificity among selectors. A class can be applied to multiple elements and one element can have multiple classes. It is selected with a dot in CSS like .btn. Use id for unique page landmarks like the main header or footer navigation. Use class for reusable styles like buttons, cards, or alerts. In JavaScript, getElementById is faster but getElementsByClassName returns a live HTMLCollection of all matching elements." },
      { text: "What is Flexbox in CSS? When would you use it?", answer: "Flexbox (Flexible Box Layout) is a CSS layout model that makes it easy to align and distribute items within a container along one axis. You enable it with display: flex on the parent element. Key properties: flex-direction sets row or column, justify-content aligns along the main axis (center, space-between, space-around), align-items aligns along the cross axis, flex-wrap allows items to wrap to next line, and gap sets spacing between items. Use Flexbox for: navigation bars, centering content both vertically and horizontally, distributing items in a row or column, and any one-dimensional layout." },
      { text: "What does the meta viewport tag do in HTML?", answer: "The meta viewport tag controls how a webpage is displayed on mobile devices. Without it, mobile browsers zoom out to render the full desktop version of the site, making text tiny. The standard tag is: meta name=viewport content=width=device-width initial-scale=1.0. The width=device-width setting makes the page width match the device screen width, and initial-scale=1.0 sets the initial zoom level to 100% with no zoom. This tag is essential for responsive design to work correctly — without it, media queries may not trigger as expected on mobile browsers." },
      { text: "What is the difference between px, em, and rem in CSS?", answer: "px (pixels) is an absolute unit — 16px is always 16 pixels regardless of context, good for borders and fine details. em is relative to the font-size of the parent element — if the parent is 16px then 1.5em equals 24px. This can cause compounding problems when elements are nested deeply. rem (root em) is relative to the root html element font-size — so 1rem equals 16px everywhere by default, regardless of nesting. This makes rem much more predictable. Best practice: use rem for font sizes and spacing, px for borders and shadows, and percentage or viewport units like vw and vh for widths and heights." },
      { text: "What is semantic HTML? Give examples of semantic tags.", answer: "Semantic HTML uses elements that describe the meaning and purpose of content rather than just its visual appearance. This helps browsers, search engines, and assistive technologies understand the page structure. Examples of semantic elements: header (page or section header), nav (navigation links), main (primary page content), article (self-contained content like a blog post), section (thematic grouping of content), aside (sidebar or supplementary content), footer (page or section footer), figure and figcaption (images with descriptions), and time (dates and times). Benefits include: better SEO rankings, improved accessibility for screen reader users, and cleaner more maintainable code." },
      { text: "What is the purpose of the alt attribute in an img tag?", answer: "The alt attribute provides alternative text description for an image that serves multiple purposes. First, accessibility: screen readers used by visually impaired users read the alt text aloud to describe the image. Second, SEO: search engines cannot see images but can read alt text to understand the image content and improve rankings. Third, fallback: the alt text is displayed visually when an image fails to load due to a broken link or slow connection. For purely decorative images that add no content value, use an empty alt attribute (alt equals empty string) to tell screen readers to skip it. Never omit the alt attribute entirely as that leaves screen readers without guidance." }
    ],
    Medium: [
      { text: "What is the difference between CSS Grid and Flexbox? When would you use each?", answer: "Flexbox is one-dimensional — it arranges items along either a row OR a column at a time. Grid is two-dimensional — it works with rows AND columns simultaneously, letting you place items precisely in a grid. Use Flexbox for: navigation bars, aligning items in a single row, distributing items evenly along one axis, centering a single element. Use Grid for: overall page layouts, card grids with fixed columns, magazine-style complex layouts, placing overlapping elements. They complement each other beautifully — use Grid for the page-level layout structure, then use Flexbox inside individual grid cells or components. Both can be learned together and most modern layouts use both." },
      { text: "What is CORS? Why does it exist and how do you handle it?", answer: "CORS (Cross-Origin Resource Sharing) is a browser security mechanism that blocks web pages from making requests to a different domain, protocol, or port than the one that served the page. It exists to prevent malicious websites from using your credentials to steal data from other sites you are logged into. For example, a script on evil.com cannot fetch your banking data from bank.com using your cookies. When a cross-origin request is made, the browser first sends a preflight OPTIONS request. The server must respond with Access-Control-Allow-Origin and related headers. To fix CORS in Express.js, use the cors npm package: app.use(cors({ origin: 'https://yourfrontend.com' })). Important: CORS is only enforced by browsers — Postman and server-to-server requests are not blocked." },
      { text: "Explain the concept of CSS specificity and how it works.", answer: "Specificity determines which CSS rule wins when multiple rules target the same element with conflicting styles. It is calculated as a point score with four categories: inline styles score 1000 points, id selectors score 100 points each, class selectors pseudo-classes and attribute selectors score 10 points each, and element selectors and pseudo-elements score 1 point each. The rule with the highest total specificity wins regardless of order in the stylesheet. If specificity is equal, the rule that appears later wins. The !important declaration overrides all specificity rules. Best practices: keep specificity low by using only classes, avoid !important except as a last resort, use the BEM naming methodology to prevent conflicts, and use browser DevTools to debug specificity issues." },
      { text: "What is lazy loading and how does it improve performance?", answer: "Lazy loading is a technique that defers loading of resources until they are actually needed — typically when they scroll into the viewport. Instead of loading all images when the page first loads, only images visible in the viewport are loaded initially. Benefits include: significantly faster initial page load time, reduced bandwidth usage for users who never scroll to see all images, and improved Core Web Vitals scores particularly LCP. Implementation: HTML native lazy loading with the loading=lazy attribute on img elements is the simplest approach. For JavaScript frameworks like React, use React.lazy() combined with Suspense for component-level code splitting. Route-based code splitting is especially impactful — each page loads only the JavaScript it needs." },
      { text: "What is the difference between localStorage, sessionStorage, and cookies?", answer: "localStorage persists data indefinitely until explicitly cleared by code or the user — it survives browser restarts and tab closings. Stores up to approximately 5MB of data. Accessible only by JavaScript on the client side. sessionStorage stores data only for the duration of the browser tab session — it is cleared automatically when the tab is closed. Same storage limit as localStorage. Cookies have a much smaller size limit of about 4KB but are automatically sent to the server with every HTTP request, making them essential for session-based authentication. Cookies can have an expiration date set and can be made HttpOnly (inaccessible to JavaScript) for security against XSS attacks. Use localStorage for user preferences like dark mode. Use cookies for authentication tokens that the server needs to verify." },
      { text: "What are Core Web Vitals? How would you optimize LCP, FID, and CLS?", answer: "Core Web Vitals are Google metrics measuring user experience quality. LCP (Largest Contentful Paint) measures loading performance — target under 2.5 seconds. Optimize by: preloading hero images with link rel=preload, using modern image formats like WebP, optimizing server response time with caching, and eliminating render-blocking scripts. FID (First Input Delay) or INP measures interactivity — target under 100ms. Optimize by: breaking up long JavaScript tasks, reducing third-party script impact, and using web workers for heavy computation. CLS (Cumulative Layout Shift) measures visual stability — target under 0.1. Optimize by: always specifying explicit width and height attributes on images and videos, avoiding inserting content above existing content, and using CSS transform animations instead of layout-triggering properties like top or left." },
      { text: "Explain how the browser renders a webpage (Critical Rendering Path).", answer: "The Critical Rendering Path is the sequence of steps the browser takes to render a page. (1) Parse HTML to build the DOM tree. (2) Parse CSS to build the CSSOM tree — CSS is render-blocking, the browser stops parsing HTML until CSS is downloaded and parsed. (3) Combine DOM and CSSOM to create the Render Tree — only visible elements are included. (4) Layout (Reflow): calculate the exact position and size of each element on the screen. (5) Paint: fill in pixels with colors, text, images, shadows. (6) Composite: combine painted layers in the correct order. JavaScript is also parser-blocking unless it has the async or defer attribute. Optimization strategies: minimize critical CSS, defer non-critical scripts, reduce render-blocking resources, and keep the DOM small." },
      { text: "What are Web Accessibility best practices?", answer: "Key accessibility practices every developer should follow: (1) Use semantic HTML — screen readers rely on proper heading hierarchy (h1 through h6) and landmark elements like nav, main, and footer. (2) Add descriptive alt text to all meaningful images. (3) Ensure full keyboard navigability — all interactive elements must be reachable and operable with the keyboard alone without a mouse. (4) Maintain sufficient color contrast — WCAG requires at least 4.5:1 ratio for normal text. (5) Use ARIA labels and roles when semantic HTML is not sufficient, but prefer native HTML elements first. (6) Never use color alone to convey information — add icons or text labels too. (7) Provide captions and transcripts for audio and video content. (8) Make form fields accessible with visible labels. Test with NVDA on Windows or VoiceOver on Mac." },
      { text: "What is WebSockets and how does it differ from HTTP polling?", answer: "WebSockets provide a persistent bidirectional connection between client and server over a single TCP connection. Once established, both sides can send messages to each other at any time without a new request. HTTP polling is when the client repeatedly sends requests to the server at regular intervals to check for new data, even when nothing has changed — this is inefficient and adds unnecessary load. Long polling is an improvement where the server holds the connection open until there is new data to send. WebSockets are ideal for: real-time chat applications, live collaboration tools like Google Docs, live sports scores, stock tickers, and multiplayer games. The server initiates messages to the client, which is impossible with standard HTTP. In Node.js, Socket.io is the most popular library for WebSocket implementation with fallback support." },
      { text: "What is Content Security Policy and why is it important?", answer: "Content Security Policy (CSP) is an HTTP response header that tells browsers which sources of content are trusted for your website. It acts as a second layer of defense against XSS attacks by preventing the browser from executing malicious scripts injected by attackers. Example header: Content-Security-Policy: default-src self; script-src self cdn.example.com; style-src self unsafe-inline. This tells the browser to only load scripts from your own domain and cdn.example.com, blocking any other script sources including injected malicious code. Use Content-Security-Policy-Report-Only mode first to test without breaking anything. Use nonces or hashes instead of unsafe-inline for inline scripts. Combine with other security headers: X-Frame-Options prevents clickjacking, X-Content-Type-Options prevents MIME sniffing." },
      { text: "What are service workers? How do they enable offline functionality?", answer: "Service workers are JavaScript files that run in the background in a separate thread from the main browser, acting as programmable network proxies. They intercept all network requests from your web application and can serve cached responses when offline. Lifecycle stages: Register (browser downloads service worker file), Install (cache specified assets in Cache Storage), Activate (take control and clean old caches), Fetch (intercept network requests). Cache strategies: Cache First serves from cache and falls back to network — ideal for static assets. Network First tries the network and falls back to cache — ideal for dynamic API data. Stale While Revalidate serves cached version immediately while updating cache in background. Service workers also power Push Notifications and Background Sync. They require HTTPS to work (localhost is an exception for development)." }
    ],
    Hard: [
      { text: "How would you debug a memory leak in a web application?", answer: "Memory leaks occur when memory is allocated but never released. Common causes in web apps: forgotten event listeners not removed when components unmount, closures that hold references to large objects, variables accidentally stored in global scope, detached DOM nodes still referenced in JavaScript, and setInterval calls without corresponding clearInterval. Debugging process: (1) Open Chrome DevTools Memory tab and take a Heap Snapshot while the app is idle. (2) Perform the action suspected to cause the leak several times. (3) Take another Heap Snapshot and compare — objects that keep growing indicate a leak. (4) Use the Performance Monitor in DevTools to watch JS heap size over time — a steadily increasing line indicates a leak. (5) Record a Memory Allocation Timeline to see exactly where allocations happen. (6) Look for Detached DOM Tree nodes in heap snapshots. Fixes: always remove event listeners in cleanup functions, use WeakMap for cache objects so they can be garbage collected, and in React always return a cleanup function from useEffect for subscriptions and timers." },
      { text: "Explain the difference between server-side rendering, client-side rendering, and static site generation.", answer: "Client-Side Rendering (CSR): The server sends a minimal HTML shell and a large JavaScript bundle. The browser downloads and executes JavaScript to build the entire page in the browser. Slow initial load because users see a blank page until JS executes, but subsequent navigation is very fast. Poor SEO without extra work since crawlers may not execute JavaScript. Examples: Create React App single-page applications. Server-Side Rendering (SSR): The server generates complete HTML for each request and sends it ready to display. Fast initial page load and excellent SEO since full content is in the HTML. Each navigation requires a server round-trip for new HTML. More server compute required. Examples: Next.js with getServerSideProps. Static Site Generation (SSG): HTML is generated at build time and served as pre-built static files from a CDN. Absolute fastest loading, best SEO, cheapest infrastructure. Content is fixed at build time — requires rebuild to update content. Examples: Next.js getStaticProps, Gatsby. Incremental Static Regeneration (ISR) in Next.js regenerates pages in the background after a configurable time interval, giving the benefits of SSG with fresher content." }
    ]
  },
  'JavaScript': {
    Easy: [
      { text: "What is the difference between var, let, and const in JavaScript?", answer: "var is function-scoped and is hoisted to the top of its function where it is initialized as undefined, meaning you can reference it before declaration without an error but its value will be undefined. var can also be redeclared in the same scope. let is block-scoped (within curly braces), hoisted but not initialized which creates a Temporal Dead Zone where accessing it before declaration throws a ReferenceError. let cannot be redeclared in the same scope. const is also block-scoped and must be assigned a value at declaration. It cannot be reassigned to a different value, but for objects and arrays the contents CAN be mutated — const prevents changing the reference not the contents. Best practice: use const by default for everything, use let only when you need to reassign, and never use var in modern JavaScript." },
      { text: "What is a closure in JavaScript? Give a simple example.", answer: "A closure is a function that retains access to variables from its outer (enclosing) scope even after that outer function has finished executing. Every function in JavaScript forms a closure over the scope where it was created. Example: function makeCounter() { let count = 0; return function() { count++; return count; }; } const counter = makeCounter(); counter() returns 1, counter() returns 2, counter() returns 3. The inner function closes over the count variable and remembers it between calls even though makeCounter() has already returned. Practical uses: creating private variables and data encapsulation, factory functions that generate customized functions, memoization, and event handlers that need to remember some state from when they were created. Understanding closures is fundamental to understanding JavaScript." },
      { text: "What is the difference between == and === in JavaScript?", answer: "The double equals == is the loose equality operator that performs type coercion before comparing values. JavaScript automatically converts one or both operands to a common type. So '5' == 5 is true because the string is converted to a number, 0 == false is true because false converts to 0, and null == undefined is true by specification. The triple equals === is the strict equality operator that compares both the value AND the type without any type conversion. So '5' === 5 is false because one is a string and one is a number. 0 === false is false. null === undefined is false. Always use === in your code because == can cause subtle and hard-to-find bugs due to unexpected type coercions. The only common acceptable use of == is the null check: if (value == null) which catches both null and undefined simultaneously." },
      { text: "What are arrow functions? How are they different from regular functions?", answer: "Arrow functions are a concise syntax for writing functions introduced in ES6: const add = (a, b) => a + b. For single expressions, the return is implicit. The most important difference from regular functions is that arrow functions do not have their own 'this' binding — they inherit 'this' from the surrounding lexical scope where they were defined. This solves a very common bug where 'this' inside a callback or setTimeout loses its expected context. Arrow functions also have no 'arguments' object (use rest parameters instead), cannot be used as constructors with the new keyword, and have no prototype property. Use arrow functions for: callbacks, array methods like map and filter, and any situation where you want 'this' to refer to the outer context. Avoid using them as object methods when you need 'this' to refer to the object itself." },
      { text: "What is the difference between null and undefined in JavaScript?", answer: "undefined means a variable has been declared but has not been assigned any value yet, or a function parameter was not provided, or an object property does not exist, or a function does not explicitly return a value. JavaScript assigns undefined automatically in these cases. null is an intentional assignment by a developer to explicitly indicate that a variable has no value or that an object reference is deliberately empty. You must set null manually. Key technical differences: typeof undefined returns the string 'undefined' while typeof null returns 'object' which is a historical bug in JavaScript that cannot be changed for backward compatibility. For strict equality, null === undefined is false. For loose equality, null == undefined is true. Best practice: use null when you want to intentionally clear a value, and let undefined arise naturally from JavaScript without setting it explicitly." },
      { text: "What is the difference between forEach and map in JavaScript?", answer: "Both forEach and map iterate over every element of an array calling a provided function for each element. The critical difference is the return value. forEach always returns undefined — it is used purely for side effects like updating external variables, logging each item, or making API calls. It does not create a new array. map returns a NEW array containing the results of calling the provided function on each element of the original array. The original array is not modified. Example: [1, 2, 3].map(x => x * 2) returns [2, 4, 6] while the original array remains [1, 2, 3]. Use map when you want to transform data and need the results in a new array. Use forEach when you just need to do something with each item and do not need the return values. In functional programming, map is heavily preferred as it does not produce side effects." },
      { text: "What is a callback function? Give an example.", answer: "A callback function is a function that is passed as an argument to another function with the intent to be executed at a later time, often after some asynchronous operation completes. The function that receives the callback decides when to call it. Example: setTimeout(function() { console.log('This runs after 2 seconds'); }, 2000). Here the anonymous function is the callback — setTimeout calls it after the delay. Array methods use callbacks extensively: [1, 2, 3, 4].filter(function(num) { return num > 2; }) passes a callback that determines which elements to keep, returning [3, 4]. Event listeners use callbacks: button.addEventListener('click', handleClick) where handleClick is called when the click event fires. The main problem with callbacks is callback hell — deeply nested callbacks for sequential async operations become unreadable, which is why Promises and async/await were created to solve this pattern." },
      { text: "How does typeof work in JavaScript? What are its limitations?", answer: "The typeof operator returns a string indicating the type of a value. Results for common types: typeof 'hello' returns 'string', typeof 42 returns 'number', typeof true returns 'boolean', typeof undefined returns 'undefined', typeof function(){} returns 'function', typeof Symbol() returns 'symbol', typeof 42n returns 'bigint'. The limitations of typeof: typeof null returns 'object' which is a famous historical bug in JavaScript — null is not an object but this cannot be fixed without breaking existing code. typeof [] also returns 'object' so you cannot distinguish arrays from plain objects using typeof alone. typeof NaN returns 'number' even though NaN means Not a Number. Solutions: use Array.isArray() to check for arrays, use value === null to check for null specifically, use Number.isNaN() to check for NaN, and use Object.prototype.toString.call(value) for precise type identification of any value." },
      { text: "What is an array and what are some common array methods?", answer: "An array is an ordered collection of values stored in a single variable, accessed by numeric index starting at zero. Arrays in JavaScript are dynamic — they can hold any combination of data types and grow or shrink automatically. Common array methods: push() adds elements to the end, pop() removes from the end, shift() removes from the beginning, unshift() adds to the beginning. Transformation methods: map() creates a new array by transforming each element, filter() creates a new array with elements passing a test, reduce() accumulates elements into a single value, flat() flattens nested arrays. Search methods: find() returns first matching element, findIndex() returns first matching index, includes() checks if value exists, indexOf() returns position. Iteration: forEach() executes a function for each element. Sorting: sort() sorts in place, reverse() reverses in place. Spread operator copies arrays: [...array1, ...array2] merges two arrays." },
      { text: "What is JSON? How do you parse and stringify JSON in JavaScript?", answer: "JSON (JavaScript Object Notation) is a lightweight text-based data format used to exchange data between a server and a web application. Despite its name, JSON is language-independent and is used across many programming languages. JSON syntax looks very similar to JavaScript objects but with important differences: all keys must be wrapped in double quotes, string values must use double quotes not single quotes, and functions, undefined, and symbols are not valid JSON values. In JavaScript, JSON.stringify(object) converts a JavaScript object or array into a JSON string for sending to a server or storing as text. JSON.parse(string) converts a JSON string back into a JavaScript object or array. Common use: const response = await fetch('/api/data'); const data = await response.json() which internally calls JSON.parse. When using JSON.stringify, you can pass a replacer and space argument to format and filter the output." }
    ],
    Medium: [
      { text: "Explain the JavaScript event loop and how asynchronous code works.", answer: "JavaScript is single-threaded meaning it can only do one thing at a time. The event loop is what enables JavaScript to handle asynchronous operations without blocking. The call stack is where synchronous code executes — functions are pushed when called and popped when they return. Web APIs provided by the browser handle async operations like setTimeout, fetch, and DOM events outside the JavaScript engine. When an async operation completes its callback is placed in the task queue (also called callback queue or macrotask queue). The event loop continuously checks: if the call stack is empty, take the first item from the microtask queue (Promise callbacks and queueMicrotask) and execute it. Process ALL microtasks until the microtask queue is empty. Then take ONE macrotask from the task queue. This is why Promises always resolve before setTimeout even with a delay of zero milliseconds — microtasks have higher priority than macrotasks." },
      { text: "What is prototypal inheritance in JavaScript?", answer: "Every JavaScript object has a hidden internal link to another object called its prototype. When you try to access a property or method on an object, JavaScript first looks on the object itself. If not found, it looks at the prototype. If not found there, it looks at the prototype's prototype, continuing up the chain until reaching null — this chain is called the prototype chain. This is how all arrays have access to methods like map and filter: Array.prototype has these methods defined, and all array instances inherit them through the prototype chain. You can set up inheritance with Object.create(parentProto) which creates a new object with the specified prototype. ES6 class syntax is syntactic sugar over prototypal inheritance — the class keyword makes it look like classical inheritance but under the hood it still uses prototypes. Unlike classical inheritance which copies properties, prototypal inheritance delegates property lookups to the prototype chain." },
      { text: "What is the difference between call(), apply(), and bind()?", answer: "All three methods allow you to explicitly set what 'this' refers to inside a function. call() invokes the function immediately and passes the desired 'this' context as the first argument, followed by individual arguments: greet.call(person, 'Hello', 'World'). apply() also invokes the function immediately with the specified 'this' but takes arguments as an array: greet.apply(person, ['Hello', 'World']). This is useful when you already have your arguments in an array format. bind() is fundamentally different — it does NOT call the function immediately. Instead it returns a new function with 'this' permanently bound to the specified context: const boundGreet = greet.bind(person). You call the returned function later, optionally with additional arguments. Common uses: use bind() for event handlers and callbacks where you need to preserve class method context, use call() to borrow methods from other objects, and use apply() when arguments are already in an array like spreading Math.max with an array." },
      { text: "Explain async/await. How does it work under the hood?", answer: "async/await is syntactic sugar built on top of Promises that makes asynchronous code look and behave like synchronous code, making it easier to read and reason about. An async function always returns a Promise — if you return a plain value, it is automatically wrapped in a resolved Promise. The await keyword can only be used inside an async function and it pauses the execution of the async function (not the entire JavaScript thread) until the awaited Promise resolves, then unwraps the resolved value. Under the hood, the JavaScript engine transforms async/await into Promise chains using generator functions. Error handling uses standard try/catch blocks which internally map to Promise rejection handling. For parallel operations, use Promise.all: const [user, posts] = await Promise.all([fetchUser(), fetchPosts()]) instead of awaiting each one sequentially which would be much slower. A common mistake is forgetting await, which causes you to work with the Promise object instead of its resolved value." },
      { text: "What is destructuring in JavaScript? Give examples for objects and arrays.", answer: "Destructuring is a JavaScript syntax that allows you to unpack values from arrays or properties from objects into distinct named variables. Array destructuring uses position: const [first, second, ...rest] = [1, 2, 3, 4, 5] gives first=1, second=2, rest=[3,4,5]. You can skip elements with empty commas: const [,, third] = [1, 2, 3] gives third=3. Swap variables without temporary: [a, b] = [b, a]. Object destructuring uses property names: const { name, age, city = 'Unknown' } = person extracts name and age and gives city a default value of Unknown if not present. Rename during destructuring: const { name: userName } = person creates a variable called userName. Nested destructuring: const { address: { street, city } } = person. In function parameters: function display({ name, age }) {} skips needing to access props.name. Very commonly used when receiving API responses, importing named exports, and working with React props." },
      { text: "What is event bubbling and event capturing in the DOM?", answer: "When an event occurs on a DOM element, it does not just affect that element — it travels through three phases. Capturing phase: the event travels from the document root down through the DOM tree to the target element. Target phase: the event reaches the actual element that triggered it. Bubbling phase: the event travels back up from the target through all ancestor elements to the root. By default, event listeners are set up in the bubbling phase — addEventListener('click', handler) — meaning parent handlers fire after child handlers. This enables the powerful pattern of event delegation: add one event listener on a parent element instead of adding listeners to many child elements. For example, add a single click listener on a ul list element to handle clicks on all li children. Access the actual clicked element with event.target. Prevent the event from continuing to bubble with event.stopPropagation(). Prevent the browser default behavior (link navigation, form submission) with event.preventDefault(). Use the third addEventListener argument true to listen in the capturing phase instead." },
      { text: "What are higher-order functions? Give examples.", answer: "A higher-order function (HOF) is any function that either takes one or more other functions as arguments, or returns a function as its result, or both. They are a core concept in functional programming. Built-in JavaScript higher-order functions on arrays: map() takes a transformation function and returns a new array, filter() takes a predicate function and returns filtered elements, reduce() takes an accumulator function and reduces an array to a single value, sort() takes a comparator function, and forEach() takes a function to execute on each element. Creating your own HOF that returns a function: function multiplier(factor) { return function(number) { return number * factor; }; } const double = multiplier(2); double(5) returns 10. Creating one that takes a function: function repeat(fn, times) { for (let i = 0; i < times; i++) fn(i); } Higher-order functions enable: code reuse, cleaner more declarative code, composing small focused functions into complex behavior, and are fundamental to React components and hooks." },
      { text: "What is the spread operator and rest parameter? When would you use them?", answer: "Both use the three-dot ... syntax but in opposite contexts with opposite purposes. The spread operator expands an iterable (array, string, or object) into individual elements. Array use cases: copy an array const copy = [...original], merge arrays const merged = [...arr1, ...arr2], pass array as individual function arguments Math.max(...numbers). Object use cases: copy an object const copy = {...original}, merge objects const merged = {...defaults, ...overrides} where later properties overwrite earlier ones, and create a modified copy without mutation const updated = {...user, name: 'New Name'}. The rest parameter collects multiple individual elements into an array. In function definitions, it must be the last parameter: function sum(...numbers) { return numbers.reduce((a, b) => a + b, 0) } which allows calling sum(1, 2, 3, 4). In destructuring: const [first, ...remaining] = array gives the rest as an array. Key distinction: spread is at the call site expanding values out, rest is at the definition site collecting values in." },
      { text: "Explain the concept of hoisting in JavaScript.", answer: "Hoisting is JavaScript's behavior during the compilation phase (before code executes) of moving declarations to the top of their containing scope. Variable declarations with var are hoisted and initialized to undefined, so accessing a var variable before its declaration line does not throw an error but returns undefined. Function declarations are fully hoisted — both the declaration and the function body — meaning you can call a function before it appears in the code and it works perfectly. let and const declarations are also hoisted to the top of their block scope but they are NOT initialized. Accessing them before their declaration line throws a ReferenceError. The zone between the top of the scope and the let/const declaration is called the Temporal Dead Zone (TDZ). Function expressions and arrow functions assigned to variables behave according to the variable type: var ones return undefined if called before initialization, let and const ones throw a ReferenceError. Best practice: always declare variables at the top of their scope and define functions before calling them to avoid confusion." }
    ],
    Hard: [
      { text: "Explain JavaScript's memory management and garbage collection.", answer: "JavaScript automatically manages memory through garbage collection so developers rarely need to think about manual allocation and deallocation. The memory lifecycle has three stages: allocation when variables and objects are created, usage when they are read and written, and release when they are no longer needed. V8 (Node.js and Chrome's JavaScript engine) uses a generational garbage collection strategy. Memory is divided into the Young Generation (where new short-lived objects are allocated, collected frequently and quickly with a minor GC) and the Old Generation (where objects that survived multiple young GC cycles are promoted, collected less frequently with a major GC using mark-and-sweep). The mark-and-sweep algorithm marks all objects reachable from roots like global variables and the call stack, then sweeps and frees all unreachable objects. Memory leaks happen when objects remain reachable unintentionally: forgotten event listeners that reference DOM nodes, closures that capture large objects, global variables that accumulate data, and setInterval without clearInterval. Use Chrome DevTools Memory panel and heap snapshots to identify leaks." },
      { text: "What is the difference between microtasks and macrotasks in the event loop?", answer: "The event loop processes two types of task queues with different priorities. Macrotasks (the task queue) include: setTimeout callbacks, setInterval callbacks, setImmediate (Node.js), I/O callbacks, and UI rendering events. Only ONE macrotask is processed per event loop iteration before the loop checks again. Microtasks (the microtask queue) include: Promise.then, Promise.catch, Promise.finally callbacks, and queueMicrotask() calls. ALL pending microtasks are processed after each task and after each microtask — even microtasks added during microtask processing run before any macrotask. This means microtasks can potentially starve macrotasks if they keep adding new microtasks. Practical consequence: console.log(1); setTimeout(() => console.log(2), 0); Promise.resolve().then(() => console.log(3)); console.log(4) outputs 1, 4, 3, 2. The synchronous code runs first (1 then 4), then all microtasks (Promise gives 3), then the macrotask (setTimeout gives 2). Understanding this order is crucial for reasoning about async code behavior." },
      { text: "Explain memoization and implement a memoize function from scratch.", answer: "Memoization is an optimization technique where the results of expensive function calls are cached and returned when the same inputs are used again, avoiding redundant computation. It is only applicable to pure functions where the same inputs always produce the same output. Implementation from scratch: function memoize(fn) { const cache = new Map(); return function(...args) { const key = JSON.stringify(args); if (cache.has(key)) { console.log('Cache hit'); return cache.get(key); } const result = fn.apply(this, args); cache.set(key, result); return result; }; } Usage example: const memoizedFibonacci = memoize(function fib(n) { if (n <= 1) return n; return memoizedFibonacci(n-1) + memoizedFibonacci(n-2); }). In React, useMemo and useCallback are built-in memoization for computed values and functions respectively. Real-world applications: caching API responses, heavy mathematical computations, and recursive algorithms like dynamic programming. Limitations: JSON.stringify as a key does not work for functions or circular references as arguments, and memory usage grows unbounded without a cache eviction strategy." }
    ]
  },
  'React': {
    Easy: [
      { text: "What is React and why would you use it over plain JavaScript?", answer: "React is a JavaScript library developed by Facebook for building user interfaces, particularly Single Page Applications where the UI needs to update dynamically without full page reloads. Key advantages over plain JavaScript: (1) Component-based architecture — you build encapsulated reusable pieces of UI that manage their own state, making large codebases much more manageable and maintainable. (2) Declarative programming — you describe WHAT the UI should look like based on state rather than HOW to update the DOM step by step. React figures out the minimal DOM updates needed. (3) Virtual DOM — React maintains a lightweight copy of the DOM in memory and uses a diffing algorithm to calculate and batch the minimum necessary real DOM changes, keeping UI updates efficient. (4) Unidirectional data flow — data flows one way making state changes predictable and easier to debug. (5) Massive ecosystem — React Router, Redux, Next.js, React Native for mobile. Use React for complex dynamic UIs with many state-dependent views." },
      { text: "What is JSX? Why do we use it in React?", answer: "JSX (JavaScript XML) is a syntax extension for JavaScript that allows you to write HTML-like markup directly inside JavaScript code. It is not valid JavaScript — a build tool like Babel compiles it to React.createElement() function calls before it reaches the browser. For example, const element = <h1 className='title'>Hello World</h1> compiles to React.createElement('h1', { className: 'title' }, 'Hello World'). JSX is used because it makes component code much more readable and intuitive compared to nested createElement calls. It also allows IDEs to provide better syntax highlighting and error checking. Important differences from HTML: class must be written as className, for must be htmlFor, all tags must be explicitly closed including self-closing like img and input, and JavaScript expressions are embedded with curly braces like {user.name} or {isLoggedIn ? 'Welcome' : 'Please login'}. JSX is optional in React but essentially universal in practice." },
      { text: "What are props in React? How do you pass data between components?", answer: "Props (short for properties) are the mechanism for passing data from a parent component down to a child component, similar to function arguments. They are read-only — a child component must never modify its own props. Parent passes props by adding attributes to the child component in JSX: <UserCard name='John' age={25} isAdmin={true} onClick={handleClick} />. The child receives all props as a single object: function UserCard(props) { return <div>{props.name}</div>; } or using destructuring: function UserCard({ name, age, onClick }) { return <div onClick={onClick}>{name} is {age}</div>; }. Props can be any JavaScript value including strings, numbers, booleans, objects, arrays, functions, and even other React components (this is called children). Data flows strictly one direction from parent to child. To pass data upward from child to parent, the parent passes a callback function as a prop, and the child calls it with data when something happens." },
      { text: "What does the useState hook do? Give an example.", answer: "useState is a React hook that allows functional components to have their own state — a value that can change over time and when changed causes the component to re-render with the new value. The useState function takes an initial value as its argument and returns an array with exactly two items: the current state value and a setter function to update it. You typically destructure this immediately: const [count, setCount] = useState(0). The initial value 0 is only used on the first render. To update state, call the setter function: setCount(5) or setCount(count + 1). Calling the setter with a new value causes React to re-render the component with that new state value. For updates that depend on the previous state value, use the functional form: setCount(prevCount => prevCount + 1) — this is safer in async situations and batch updates. Each useState call is completely independent from others in the same component." },
      { text: "What is the virtual DOM in React and how does it work?", answer: "The Virtual DOM (VDOM) is a lightweight in-memory JavaScript representation of the actual browser DOM. React keeps a virtual DOM tree that mirrors the real DOM structure. When component state or props change: React creates a new virtual DOM tree representing what the UI should look like. React then diffs (compares) the new virtual DOM against the previous virtual DOM snapshot — this process is called reconciliation. The diffing algorithm identifies the minimal set of differences. Finally, React applies only those specific changes to the real browser DOM rather than re-rendering everything. This is efficient because direct DOM manipulation is slow — reading or writing to the real DOM triggers browser layout recalculations, paint operations, and composite operations. By batching DOM updates and minimizing their number, React keeps interfaces responsive and fast. The reconciliation algorithm uses the key prop on list items to efficiently match old and new elements." },
      { text: "What is the purpose of the key prop when rendering lists in React?", answer: "The key prop is a special attribute that helps React identify which items in a rendered list have changed, been added, or been removed between renders. Without keys, React cannot efficiently update lists and may re-render all items, cause incorrect behavior with stateful components, or lose input values in form elements. When state changes and a list re-renders, React uses keys to match elements from the new list to elements from the previous list. A matched element gets its existing DOM node updated rather than destroyed and recreated. Keys must be unique among siblings in the same list and stable — they must not change between renders. Using the array index as a key is an antipattern when the list can be reordered, filtered, or items added to the middle, because indices change and React gets confused. Always use a stable unique identifier from your data like a database id: {items.map(item => <Item key={item.id} data={item} />)}." },
      { text: "What is the difference between a functional component and a class component?", answer: "Class components are JavaScript classes that extend React.Component. They require a render() method that returns JSX, manage state via this.state object and this.setState(), and handle side effects with lifecycle methods like componentDidMount, componentDidUpdate, and componentWillUnmount. They require the this keyword to access props, state, and methods. Functional components are plain JavaScript functions (or arrow functions) that accept a props argument and return JSX. With the introduction of React Hooks in version 16.8, functional components gained the ability to use state with useState, side effects with useEffect, and all other React features. Functional components are now the strongly recommended standard. They are simpler to write and read, require significantly less boilerplate code, avoid confusion around the this keyword, are easier to test, and perform slightly better. Class components are still fully supported and work fine but React is not adding new features to them." },
      { text: "What is state in React? How is it different from props?", answer: "State is data that is managed INSIDE a component that can change over time. When state changes, React automatically re-renders the component to reflect the new state. State is private and fully controlled by the component that owns it. Props are data that comes FROM OUTSIDE the component — passed by a parent component. The child component cannot and should not directly modify its props. Key differences: State is mutable using the useState setter function or setState, while props are read-only from the child's perspective. State is initialized and lives inside the component, props are provided by the parent. State changes trigger a re-render of that component and its children, prop changes cause a re-render of the component receiving the new props. Use state for: things that change due to user interaction like form input values, toggle states, or data fetched from an API. Use props for: passing data to display, configuration settings, and event handler callbacks. A component can have both — it receives props from its parent and manages its own state." },
      { text: "How do you handle events in React? How is it different from HTML?", answer: "React events use camelCase naming conventions rather than lowercase: onClick not onclick, onChange not onchange, onSubmit not onsubmit. Event handlers are passed as functions in curly braces rather than as strings: onClick={handleClick} not onclick='handleClick()'. React uses a SyntheticEvent system — React wraps native browser events in a cross-browser compatible synthetic event that has the same interface as native events but works consistently across all browsers. To prevent the default browser behavior like link navigation or form submission, call event.preventDefault() inside your handler. React uses event delegation under the hood — instead of attaching a listener to each DOM element, React attaches a single listener at the root of your app and routes events to the correct handler, which is more efficient for large component trees. In React 17 and later, events delegate to the root element instead of the document object. The event object is passed automatically as the first argument to your handler function." },
      { text: "What is a React fragment and why would you use it?", answer: "A React Fragment is a way to group multiple JSX elements together without adding an extra DOM node. The problem it solves: JSX expressions must have a single root element. The naive solution of wrapping everything in a div adds unnecessary markup to the DOM which can break layouts particularly with CSS Grid and Flexbox, interfere with styling, and create invalid HTML in some contexts like table rows. Fragments solve this cleanly. Short syntax using empty tags: <><Child1 /><Child2 /></>. Explicit syntax when you need to add a key prop (required in lists): <React.Fragment key={item.id}><td>{item.name}</td><td>{item.value}</td></React.Fragment>. The short empty tag syntax does not support the key prop. Common use cases: returning multiple elements from a component, rendering table rows where each row renders multiple cells, and any time an extra wrapper div would create invalid HTML or break layout." }
    ],
    Medium: [
      { text: "What is the useEffect hook? Explain its dependency array.", answer: "useEffect is a React hook for performing side effects in functional components — operations that interact with the outside world like fetching data, subscribing to external events, manually updating the DOM, or setting up timers. The hook takes two arguments: a function containing the side effect code, and an optional dependency array. The dependency array controls when the effect runs: no second argument means the effect runs after every single render. An empty array [] means the effect runs only once after the initial mount (like componentDidMount). An array with values [dep1, dep2] means the effect runs after the initial mount and again whenever any value in the dependency array has changed since the last render. The effect function can optionally return a cleanup function that runs before the next effect execution and when the component unmounts — use this to cancel subscriptions, clear timers, and abort fetch requests to prevent memory leaks and state updates on unmounted components. Always include all values from the component scope that are used inside the effect in the dependency array." },
      { text: "What is the Context API? When would you use it over props?", answer: "The Context API is a way to share data across multiple components at different levels of the component tree without manually passing props through every intermediate component (avoiding prop drilling). Three steps to use it: Create a context with React.createContext(defaultValue) which returns a context object. Provide the context value high in the component tree with context.Provider: <ThemeContext.Provider value={currentTheme}><App /></ThemeContext.Provider>. Consume the context in any descendant component with the useContext hook: const theme = useContext(ThemeContext). Good use cases: authentication state (current logged-in user needed in many components), theme (dark or light mode preferences), language and locale settings, and data needed by many components at different nesting depths. Avoid using Context for: data that only 2-3 closely related components need (pass props instead), and very high-frequency updates like typing in an input field (every keystroke would re-render all consumers). For complex global state with frequent updates, consider dedicated state management libraries like Zustand or Redux." },
      { text: "What is useCallback and useMemo? When should you use them?", answer: "Both hooks are performance optimizations that prevent unnecessary work by memoizing values between renders. useMemo memoizes the RESULT of an expensive calculation and only recomputes it when its dependencies change: const sortedList = useMemo(() => heavySortOperation(list), [list]). The calculation only re-runs when list changes, not on every render. useCallback memoizes a FUNCTION DEFINITION and only creates a new function when its dependencies change: const handleClick = useCallback((id) => { doSomething(id, userId); }, [userId]). Without useCallback, a new function is created on every render which can trigger unnecessary re-renders in child components that receive it as a prop. When to use them: useMemo for expensive computations applied to large data sets like filtering or sorting thousands of items. useCallback when passing callback functions to child components wrapped with React.memo to prevent those children from re-rendering just because the parent re-rendered. Critical advice: do NOT add these hooks everywhere preemptively. They have their own overhead. Profile your app first with React DevTools, identify actual performance bottlenecks, then apply these hooks selectively." },
      { text: "What is lifting state up in React? When would you do it?", answer: "Lifting state up means moving state from a child component to its closest common ancestor (parent) when multiple sibling components need to access or modify the same data. Without lifting state, siblings cannot directly share data — they can only communicate through their shared parent. Classic example: a temperature converter application with both Celsius and Fahrenheit input fields. Both inputs need to stay synchronized — when one changes the other should update. The solution: lift the temperature value up to the parent component which then passes the current value and an onChange handler as props to both input components. When to lift state: when two sibling components need to access or update the same data, when a child's actions need to affect a sibling or ancestor component, or when you need a single source of truth for data used in multiple places. Potential downsides: can lead to prop drilling through many intermediate components if the tree is deep. Solutions for deeply nested sharing: Context API for semi-global data, or state management libraries like Zustand for complex cases." },
      { text: "What is prop drilling and how do you avoid it?", answer: "Prop drilling is the practice of passing props through multiple intermediate component layers just to get data from a top-level component to a deeply nested component that actually needs it. The middle layer components do not use the data themselves — they just pass it along as a relay. This creates problems: intermediate components become cluttered with irrelevant props they do not use, refactoring any component in the chain requires changes throughout, and it becomes difficult to track where data comes from. Solutions: (1) React Context API — best for truly global or semi-global data like authenticated user, theme, or language preferences. Create a context, wrap the tree with a Provider, and consume directly in any descendant with useContext. (2) Component composition — instead of passing data through intermediaries, pass components as children or props. The parent can render the deeply nested component directly. (3) State management libraries — Zustand, Redux, or Jotai allow any component to read from and write to a global store without prop chains. (4) Sometimes the best solution is rethinking component structure so components that share data are closer together in the tree." },
      { text: "How does React.memo work and when should you use it?", answer: "React.memo is a higher-order component that wraps your component and memoizes it. When a parent re-renders, a memoized child component will skip re-rendering if its props have not changed. React.memo does a shallow comparison of props by default — it compares each prop with Object.is() which is similar to strict equality. Usage: const MemoizedCard = React.memo(function Card({ title, count }) { return <div>{title}: {count}</div>; }). For custom comparison logic, pass a comparison function as the second argument: React.memo(Component, (prevProps, nextProps) => prevProps.id === nextProps.id). When to use: pure display components that render frequently with the same props, list items in large lists where each item is expensive to render, and components deep in the tree that receive stable primitive props. When React.memo helps the most: the parent re-renders often but the child's props rarely change, and the child is expensive to render. Important: for React.memo to work with object or function props, those props must maintain the same reference between renders using useMemo and useCallback in the parent — otherwise new objects are created every render and memo sees them as changed." },
      { text: "What are React hooks rules? Why can't hooks be used inside conditions?", answer: "React has two fundamental rules for hooks. First: only call hooks at the top level of your function component — never inside loops, if statements, nested functions, or after early returns. Second: only call hooks from React function components or custom hooks — never from regular JavaScript functions, class components, or event handlers. The reason for the first rule is critical to understand: React identifies which useState or useEffect corresponds to which piece of state by the ORDER in which hooks are called. React does not use the variable name or any other identifier — just the call order. On every render, React expects hooks to be called in exactly the same order. If you put a hook inside a conditional, some renders might execute it and others might not, changing the call order. This breaks React's internal bookkeeping and causes hooks to be associated with the wrong state. For example, if component has hooks in order A, B, C but a condition skips B, then on that render React sees A, C and incorrectly maps C's state to what it thinks is B. Always use the eslint-plugin-react-hooks which enforces these rules automatically." },
      { text: "Explain the React component lifecycle (with hooks).", answer: "Functional components with hooks have equivalent lifecycle behavior to class components. Mounting phase (component appears): the component function runs and returns JSX for the initial render. useEffect with an empty dependency array runs after the first render — use this for initial data fetching, setting up subscriptions, or initializing third-party libraries that need DOM access. Updating phase (state or props change): the component function re-runs with new values and re-renders. useEffect with specific dependencies runs when any of those dependencies change between renders — use this to respond to specific prop or state changes, like fetching new data when an id prop changes. Unmounting phase (component disappears): the cleanup function returned from useEffect runs when the component unmounts — use this to cancel network requests with AbortController, clear setTimeout and setInterval, remove event listeners, and unsubscribe from data streams. The cleanup function also runs before each re-execution of the effect when dependencies change. The order within a render cycle: render (component function runs) → browser paints the DOM → layout effects (useLayoutEffect) → effects (useEffect)." }
    ],
    Hard: [
      { text: "How does React's reconciliation algorithm (Fiber) work?", answer: "React Fiber is a complete rewrite of React's core algorithm released in React 16. The fundamental innovation is making reconciliation (the process of comparing old and new virtual DOM trees) interruptible and prioritized. In the old architecture, reconciliation was synchronous and recursive — once started it could not be paused, potentially blocking the main thread for hundreds of milliseconds during large updates, causing dropped frames and janky UI. Fiber introduces a unit of work called a fiber node — a plain JavaScript object representing each component instance with links to its parent, child, and sibling fibers. Rendering now happens in two phases: the Render Phase (also called the reconciliation or work-in-progress phase) is asynchronous and interruptible — React can pause this work, discard it, or restart it based on priority. During this phase React walks the fiber tree, processes each fiber, and marks nodes with effect tags. The Commit Phase is synchronous and cannot be interrupted — React applies all the DOM mutations collected during the render phase. Fiber enables: Concurrent Mode with useTransition for low-priority updates, Suspense, streaming server rendering, and priority-based scheduling of updates." },
      { text: "Explain the useReducer hook. When would you use it over useState?", answer: "useReducer is an alternative to useState for managing more complex state logic. It takes a reducer function and an initial state: const [state, dispatch] = useReducer(reducer, initialState). The reducer is a pure function that receives the current state and an action object, and returns the next state: function reducer(state, action) { switch(action.type) { case 'increment': return { count: state.count + 1 }; case 'decrement': return { count: state.count - 1 }; case 'reset': return initialState; default: throw new Error('Unknown action'); } }. You update state by dispatching actions: dispatch({ type: 'increment' }) or dispatch({ type: 'add', payload: 5 }). Use useReducer over useState when: state logic is complex with multiple sub-values that update together, the next state depends on the previous state in non-trivial ways, you have multiple related state transitions that would be cleaner as named actions, or you want to model explicit state transitions like a finite state machine. The Redux pattern is essentially useReducer plus Context API for global state. Testing is also easier since the reducer is a pure function that can be tested independently without any React context." },
      { text: "How would you optimize a React app that has performance issues?", answer: "Approach performance optimization systematically. Step one: profile first — use React DevTools Profiler to record a session and identify which components re-render unnecessarily and how long each render takes. Do not optimize speculatively. Step two: prevent unnecessary re-renders — wrap expensive child components with React.memo, use useCallback to stabilize function props passed to memoized children, and use useMemo for expensive derived computations. Step three: reduce the scope of re-renders — colocate state close to where it is used rather than keeping everything at the top level so fewer components re-render on each state change. Step four: virtualize long lists — if rendering hundreds or thousands of items use react-virtual or react-window which render only the visible items. Step five: code splitting — use React.lazy and Suspense to split your bundle by route so users only download the code for the current page. Step six: optimize Context usage — Context re-renders all consumers when value changes, so split contexts by update frequency or use context selector libraries. Step seven: React 18 concurrent features — use useTransition to mark non-urgent state updates as low priority, keeping the UI responsive during heavy work." }
    ]
  },
  'Node.js': {
    Easy: [
      { text: "What is Node.js and what makes it different from browser JavaScript?", answer: "Node.js is a JavaScript runtime environment built on Chrome's V8 JavaScript engine that allows JavaScript to run on the server-side outside of a browser. Before Node.js, JavaScript could only run in browsers. Key differences from browser JavaScript: Node.js has no access to browser APIs like the DOM, document, window, localStorage, or navigator — these simply do not exist in a server environment. Instead Node.js provides server-specific APIs: the fs module for file system access, the http module for creating servers, the os module for operating system information, the path module for file paths, and the process object for environment and process control. Node.js uses CommonJS modules with require() and module.exports by default though ES Modules with import and export are also supported. Node.js can access the local file system, make arbitrary network connections, and interact with the operating system — capabilities that browsers restrict for security. Node.js uses an event-driven non-blocking I/O model powered by libuv, making it excellent for handling many simultaneous connections efficiently." },
      { text: "What is Express.js? Why do developers use it with Node.js?", answer: "Express.js is a minimal, fast, and unopinionated web application framework for Node.js. While Node.js has a built-in http module that can create servers, it is very low-level — you would need to manually parse URLs, request bodies, handle routing with complex if/else chains, and set response headers for every endpoint. Express provides higher-level abstractions that make building web servers and APIs much more developer-friendly. Key features: an intuitive routing system that maps HTTP methods and URL patterns to handler functions like app.get('/users/:id', handler), a middleware pipeline where you can chain functions that process requests in sequence for logging, authentication, parsing request bodies, and error handling, convenient response methods like res.json() and res.status(), and easy integration with template engines for server-rendered HTML. Express follows the middleware pattern inspired by Ruby's Rack and is deliberately minimal — it does not impose folder structure or architectural decisions. It is the most popular Node.js framework with millions of projects using it, though Fastify is gaining popularity for better performance and TypeScript support." },
      { text: "What is JWT (JSON Web Token)? How does authentication work with JWT?", answer: "JWT is a compact URL-safe token format for securely transmitting information between parties as a digitally signed JSON object. A JWT consists of three base64url-encoded parts separated by dots: the Header (specifies the token type and signing algorithm like HMAC SHA256), the Payload (contains claims — encoded data like userId, email, role, and token expiry time exp), and the Signature (created by signing the header plus payload with a secret key). The signature is what makes JWTs trustworthy — the server can verify the signature to confirm the token was not tampered with. Authentication flow: user submits username and password, server verifies credentials against database, server creates a JWT with user data in the payload and signs it with a secret key, server sends the token to the client, client stores the token (preferably in an httpOnly cookie for security, or in memory), client includes the token in subsequent requests in the Authorization header as Bearer token, server receives requests, verifies the JWT signature, decodes the payload to identify the user, and responds. JWTs are stateless — no server-side session storage needed." },
      { text: "What is middleware in Express.js? Give an example.", answer: "Middleware functions are the backbone of Express applications. They are functions that have access to the request object (req), the response object (res), and the next function in the pipeline. Each middleware can: read and modify request and response objects, end the request-response cycle by sending a response, or call next() to pass control to the next middleware function in the stack. If a middleware does not end the cycle and does not call next(), the request hangs. Simple logging middleware example: app.use((req, res, next) => { console.log(`${new Date().toISOString()} ${req.method} ${req.url}`); next(); }). The app.use() registers middleware for all routes. Order matters — middleware runs in the order it is registered. Common built-in middleware: express.json() parses JSON request bodies, express.static() serves static files. Popular third-party middleware: cors() handles cross-origin requests, helmet() sets security headers, express-rate-limit limits request rate, morgan provides structured request logging. Error handling middleware has four parameters (err, req, res, next) and must be registered after all routes." },
      { text: "What is the difference between SQL and NoSQL databases? When would you choose MongoDB?", answer: "SQL databases like PostgreSQL and MySQL store data in structured tables with fixed schemas, support complex multi-table JOIN queries, and provide ACID transaction guarantees (Atomicity, Consistency, Isolation, Durability). They are excellent for relational data where entities have clear relationships. NoSQL databases come in several types: document (MongoDB), key-value (Redis), wide-column (Cassandra), and graph (Neo4j). They offer flexible schemas, horizontal scaling, and different trade-offs on consistency. Choose MongoDB when: your data structure varies between records and a flexible schema would prevent constant migrations, you are building with JavaScript and Node.js since MongoDB stores BSON which maps naturally to JSON and JavaScript objects, you need rapid prototyping where the schema evolves frequently, your data is hierarchical or nested and fits naturally in documents, or you need to scale horizontally across many servers. Choose PostgreSQL when: your data is highly relational with many entity relationships requiring JOINs, you need strict ACID compliance for financial transactions, you perform complex analytical queries with aggregations and window functions, or you need strong data integrity through constraints, triggers, and foreign keys." }
    ],
    Medium: [
      { text: "Explain the Node.js event loop. How does it handle async operations?", answer: "Node.js achieves non-blocking I/O through its event loop powered by the libuv C library. Despite JavaScript being single-threaded, libuv uses a thread pool (4 threads by default) for operations that would otherwise block: file system operations, DNS lookups, and crypto operations. Network I/O uses the OS's non-blocking event notification system (epoll on Linux, kqueue on macOS) which is even more efficient. The event loop runs in phases: Timers phase executes callbacks scheduled by setTimeout and setInterval whose delay has expired. Pending Callbacks phase runs I/O error callbacks from the previous iteration. Poll phase retrieves new I/O events — the event loop waits here if no other work is pending, up to a calculated timeout. Check phase runs setImmediate callbacks — these always run after Poll completes. Close Callbacks phase handles socket close events. Between each phase, the event loop processes all pending process.nextTick callbacks and then all resolved Promise callbacks (microtasks). This architecture allows Node.js to handle thousands of simultaneous connections efficiently — while waiting for one database query, it serves other requests." },
      { text: "How do you handle errors in Express.js? What is error middleware?", answer: "Robust error handling in Express requires multiple layers working together. Synchronous errors thrown inside route handlers are automatically caught by Express. Asynchronous errors must be explicitly passed to next(): router.get('/user', async (req, res, next) => { try { const user = await User.findById(req.params.id); res.json(user); } catch (error) { next(error); } }). A cleaner pattern is an async wrapper utility: const asyncHandler = fn => (req, res, next) => Promise.resolve(fn(req, res, next)).catch(next) which eliminates try/catch from every route. Error middleware is a special middleware with exactly four parameters — the error object as the first parameter: app.use((err, req, res, next) => { const statusCode = err.statusCode || 500; const message = err.message || 'Internal Server Error'; console.error(err.stack); res.status(statusCode).json({ error: message }); }). This must be registered LAST after all routes and other middleware. You can create custom error classes with specific status codes. For unhandled Promise rejections: process.on('unhandledRejection', (reason) => { console.error(reason); server.close(() => process.exit(1)); })." },
      { text: "How would you implement rate limiting in a Node.js API?", answer: "Rate limiting protects your API from abuse, brute force attacks, and denial of service by limiting how many requests a client can make within a time window. In Express, the most straightforward approach uses the express-rate-limit package: const rateLimit = require('express-rate-limit'); const apiLimiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 100, message: { error: 'Too many requests from this IP, please try again after 15 minutes' }, standardHeaders: true, legacyHeaders: false }); app.use('/api/', apiLimiter). This limits each IP address to 100 requests per 15 minutes. For stricter protection on authentication endpoints: const authLimiter = rateLimit({ windowMs: 60 * 60 * 1000, max: 5, skipSuccessfulRequests: true }); app.post('/api/auth/login', authLimiter, loginHandler). For distributed systems with multiple server instances, in-memory rate limiting does not work because each instance has its own counter. Use rate-limit-redis to store counters in Redis shared across all instances. Additionally consider: API key based rate limiting, graduated responses (slow responses before blocking), and circuit breakers for downstream service protection." },
      { text: "Explain RESTful API design principles and best practices.", answer: "REST (Representational State Transfer) is an architectural style for designing networked APIs. Core principles and best practices: Use resource-based URLs with nouns not verbs — /api/users not /api/getUsers, /api/users/123 not /api/getUserById?id=123. Use HTTP methods to express the action: GET retrieves, POST creates, PUT replaces entirely, PATCH partially updates, DELETE removes. Use appropriate HTTP status codes: 200 OK for success, 201 Created when resource is created (include Location header), 204 No Content for successful DELETE, 400 Bad Request for validation errors, 401 Unauthorized when not authenticated, 403 Forbidden when authenticated but not authorized, 404 Not Found, 422 Unprocessable Entity for semantic validation, 500 Internal Server Error. Use consistent naming: plural nouns for collections (/users), hierarchical nesting for relationships (/users/123/orders). Implement pagination for collections: GET /users?page=2&limit=20 or cursor-based pagination for large datasets. Support filtering and sorting: GET /products?category=electronics&sort=price&order=asc. Version your API: /api/v1/users allows breaking changes without disrupting existing clients. Always return consistent JSON error objects with error code and human-readable message." }
    ],
    Hard: [
      { text: "How does Node.js handle CPU-intensive tasks without blocking the event loop?", answer: "Node.js's non-blocking architecture is ideal for I/O-bound work but struggles with CPU-intensive tasks because they run entirely in the main thread and block the event loop — preventing any other requests from being served during that time. A 5-second CPU-intensive calculation freezes the entire server for 5 seconds. Solutions in order of preference: Worker Threads (Node.js 10.5+) run JavaScript in separate threads that share the same process memory. Unlike child processes, worker threads can share memory via SharedArrayBuffer and transferable objects: const { Worker, isMainThread } = require('worker_threads'); if (isMainThread) { const worker = new Worker('./compute.js', { workerData: inputData }); worker.on('message', result => console.log(result)); } Worker threads are ideal for CPU tasks that need to run in parallel. Child Processes fork separate Node.js processes using child_process.fork() for complete isolation with IPC messaging, or child_process.spawn() to run any system command. Processes are heavier than threads but provide complete isolation. For very heavy computation, offload to external specialized services: Python for ML/data science, GPU services for image processing, or dedicated compute microservices. The cluster module creates multiple processes for the whole app to use all CPU cores, but each process still has one event loop." },
      { text: "What strategies would you use to debug a Node.js application in production?", answer: "Production debugging requires careful approaches that do not impact performance or expose sensitive data. Structured logging is the foundation: use Winston or Pino with JSON format so logs can be parsed and queried. Log at appropriate levels (error, warn, info, debug) and include request IDs for tracing requests across services. Ship logs to a centralized system like Elasticsearch with Kibana, Datadog, or CloudWatch. Error tracking with Sentry or Bugsnag automatically captures unhandled errors with full stack traces, request context, user information, and breadcrumbs showing what led to the error — invaluable for reproducing production bugs. APM (Application Performance Monitoring) tools like Datadog APM, New Relic, or OpenTelemetry provide distributed tracing so you can see exactly how long each part of a request takes including database queries and external API calls. For memory leaks in production: expose a diagnostic endpoint that can trigger a heapSnapshot on demand and download it for analysis in Chrome DevTools. PM2 provides process management with automatic restarts, cluster mode, memory limit restarts, and process metrics. Set up alerting on error rate spikes, p95 response time increases, and memory usage thresholds using your monitoring platform. For Node.js inspector remote debugging: node --inspect=0.0.0.0:9229 app.js and use SSH tunneling for secure access — use with extreme caution in production." }
    ]
  },
  'HR Questions': {
    Easy: [
      { text: "Tell me about yourself and your background.", answer: "Use the Present-Past-Future structure and keep it under 2 minutes. Present: Start with your current role and key specialization. Past: Briefly cover 2-3 relevant achievements or career milestones that got you here. Future: Connect to this specific opportunity and why you are excited about it. Example: 'I am currently a frontend developer with 3 years of experience specializing in React applications and component libraries. I started my career as a computer science graduate at a startup where I built their customer dashboard from scratch which reduced support tickets by 30%. Most recently at my current company I have been leading a team of 3 developers building a real-time analytics platform. I am looking for a senior role where I can take on more architectural responsibilities and mentor others, which is exactly what this position offers.' Avoid: listing every job from your resume chronologically, including irrelevant personal details, or going over 2 minutes. The goal is to tell a compelling career story that naturally leads to why you are the right person for this specific role." },
      { text: "Why are you interested in this position?", answer: "This question tests whether you have done research and whether your motivations are genuine and role-specific. Structure your answer in three parts: (1) Something specific about the company that genuinely appeals to you — their product, mission, market position, recent achievements, or engineering culture. (2) How this specific role aligns with your skills and what you uniquely bring to it. (3) What growth opportunity excites you. Research before the interview: read their engineering blog, check their tech stack on job postings and GitHub, look at recent news and funding, and understand their product and market. Example: 'I have been following your expansion into real-time payments for two years and find the technical challenges fascinating. Your engineering blog post about scaling your event streaming infrastructure was excellent — it showed a team thinking carefully about distributed systems problems I would love to work on. This senior engineer role appeals specifically because the job description mentions owning the fraud detection pipeline end-to-end, which aligns directly with my experience building ML pipelines at my current role. I also see this as the right company to grow into a staff engineer position, given your current scale.' Generic answers that could apply to any company signal lack of preparation." },
      { text: "What are your greatest strengths?", answer: "Choose 2 to 3 strengths that are directly relevant to the role, and prove each one with a brief specific example rather than just asserting you have the quality. Interviewers discount unsupported claims. Strong strengths for engineering roles with examples: Problem-solving ability — 'When we had intermittent 500 errors affecting 5% of users that had stumped the team for a week, I set up custom logging, reproduced the pattern, and traced it to a race condition in our session management. Fixed in 4 hours.' Communication — 'I regularly translate complex technical decisions for non-technical stakeholders. I created a technical debt visualization that helped our product team understand why we needed to delay feature work to refactor our authentication system.' Ownership mentality — 'I do not stop at my ticket scope. If I see related issues I flag them. Last quarter I noticed our API error rates were hiding behind success codes — I fixed that proactively before it became a customer-facing problem.' Prepare 3 strengths tailored to what the job description emphasizes. Avoid vague claims like 'I am a quick learner' without an example, and never claim perfection." },
      { text: "Where do you see yourself in 5 years?", answer: "Show ambition that is realistic and plausibly aligned with what this company can offer. Interviewers want to see that you have career direction and that you might be in it for the long term. Research the company's growth trajectory and internal career paths before answering. For a software engineer role, a strong answer covers: technical depth you want to develop, scope of impact you want to have, and any leadership or mentoring aspirations. Example: 'In 5 years I see myself as a senior or staff engineer who has developed deep expertise in distributed systems and has taken on architectural responsibilities — designing systems rather than just implementing them. I would also like to mentor junior engineers because I find that teaching accelerates my own understanding. What appeals to me about this company specifically is that you have a clear technical leadership track and are growing rapidly, which creates real opportunities for that kind of growth. I am not interested in moving entirely into management — I want to stay technical while having broader impact.' Avoid: saying you want to start your own company, claiming you want the interviewer's exact job, or being so vague about goals that you seem directionless." },
      { text: "What motivates you at work?", answer: "Be authentic and connect your motivation to intrinsic aspects of the work itself rather than external rewards like salary or recognition, even if those matter to you. The most compelling motivators for engineering roles: meaningful impact — seeing how your technical work solves real problems for real users, intellectual challenge — working on difficult problems that require creative thinking and continuous learning, craftsmanship — the satisfaction of building something well-architected and maintainable, collaboration — working with talented people you can learn from and contribute to, and ownership — having real responsibility over a product area. Example answer: 'I am most motivated when I can clearly see the connection between my technical work and user outcomes. At my current job I built a search feature and then a month later read user reviews saying search was one of their favorite things about the product — that kind of feedback loop is very energizing. I am also driven by intellectual challenge. I do my best work on problems that are hard enough to require genuine creativity. And I am motivated by environments where I have real ownership and autonomy — when I am trusted to make technical decisions rather than just implementing tickets.' Match your answer to what the company clearly values from their culture page or engineering blog." },
      { text: "Why are you looking to leave your current job?", answer: "Answer honestly but professionally. Never speak negatively about your current employer, manager, or teammates even if the reason you are leaving is a genuinely bad situation — interviewers always see this as a red flag about your professionalism. Focus on what you are moving TOWARD rather than what you are escaping FROM. Positive professional framing for common real reasons: Limited growth — 'I have learned a tremendous amount here and am proud of what I have built, but I have reached the ceiling of what this role can teach me. I am ready for a bigger technical challenge and more ownership than is available here.' Technology — 'I want to deepen my expertise in cloud-native architecture and my current company is still working with legacy systems where that investment does not make sense.' Company uncertainty — 'The company went through an acquisition and there is genuine uncertainty about the technical direction going forward, making it the right time to find a role where I can plan for the long term.' Seeking challenge — 'I have been in this role for four years and have accomplished everything I set out to do. I am energized by the idea of new challenges.' Always end positively by connecting to what excites you about the prospective company." },
      { text: "How do you handle stress and pressure?", answer: "Show that you can perform effectively under pressure without pretending pressure never affects you — that seems dishonest. Demonstrate healthy and effective coping strategies with a real example of handling a high-pressure situation well. Key elements: acknowledge that pressure is normal in technology work, explain your specific strategies for managing it, and give an example that demonstrates effectiveness. Example: 'I have learned that most pressure comes from uncertainty about priorities or unclear timelines, so I proactively address those. When a deadline is tight I immediately communicate with stakeholders about what is realistic, get explicit priority decisions made, and then focus completely on the highest-priority items. For unexpected crises like production outages, I focus on calm methodical thinking rather than reacting emotionally — I make a written action plan, communicate status updates regularly, and do not take on more than one thing at a time. Last quarter we had a critical payment processing failure on a Friday evening. I stayed focused, formed a clear debugging plan, sent updates to the product team every 30 minutes so they could communicate with customers, and we had it resolved in under 3 hours. Honestly I often find that high-pressure situations bring out some of my clearest thinking when I approach them systematically.' The example is what makes this answer credible." },
      { text: "Do you prefer working independently or as part of a team?", answer: "The right answer acknowledges both are important and shows you are effective at both modes. Almost all professional work requires both independent focused work and close collaboration, and the ability to switch between them is what most companies need. Example: 'I genuinely enjoy and am effective at both, and I think they are complementary rather than opposed. I deeply value blocks of uninterrupted independent work time for complex problem-solving — writing challenging code or thinking through an architectural decision benefits greatly from sustained focus. At the same time, I have learned that great software is fundamentally a team sport. I get significantly better outcomes from pair programming on difficult problems, from design reviews where colleagues spot issues I missed, and from collaborative architecture discussions where different perspectives lead to better solutions than any individual would reach alone. In my current team I probably spend about 65% of time in independent focused work and 35% in collaborative work, and I think that balance works very well. I adapt easily depending on what the situation calls for — I have also worked in much more collaborative environments with frequent pairing and that works well too when the team has the right culture.' Avoid picking one extreme as it signals poor teamwork or poor independent productivity." },
      { text: "What do you know about our company?", answer: "This question directly tests whether you prepared for this interview. Showing genuine knowledge and interest dramatically differentiates you from candidates who apply everywhere without research. What to research: the company's core product and the problem it solves, their target market and business model, their recent news (funding rounds, product launches, key hires, expansions), their tech stack from engineering blog posts and job descriptions, their company culture and values, and their main competitors. How to research: engineering blog, company LinkedIn page, Glassdoor reviews, Crunchbase for funding history, GitHub if they have open source projects, and recent press coverage. Structure your answer: start with what they do and their core value proposition, mention something specific and recent, connect to their tech or culture, and end with what personally excites you about them. Example: 'I have researched quite thoroughly. You are building a developer tooling platform that helps engineering teams manage infrastructure costs, serving primarily mid-market SaaS companies. I saw that you raised a Series B in January and are expanding the team significantly. I read your engineering blog post on how you handle multi-tenant data isolation at scale — the approach was clever and showed a team thinking carefully about the right abstractions. I noticed you are heavy users of Kubernetes and Go which aligns with my background. What personally excites me most is your mission to make infrastructure economics visible to engineering teams — I think that is a genuinely important problem.'" },
      { text: "Describe your ideal work environment.", answer: "Research the company's culture before answering and aim to be genuine while aligning with what they clearly offer. Describing an environment completely opposite to theirs signals a bad fit. Elements that resonate well at most modern tech companies: psychological safety (feeling comfortable asking questions, raising concerns, or admitting mistakes without fear of judgment), collaborative but with respect for deep work time (good balance of synchronous collaboration and focused individual work), code quality culture (regular code review, testing standards, engineering excellence valued), continuous learning opportunities (access to resources, encouragement to explore new technologies, time to learn), autonomy with clear expectations (freedom to make decisions within defined scope with clear success criteria), and cross-functional collaboration where engineers work closely with product and design from the start rather than just receiving specifications. Example: 'I thrive in environments where engineers have genuine ownership over their work — where I can make technical decisions within my scope rather than just implementing tickets handed down. I also deeply value code review culture where feedback is given generously and received as learning rather than criticism. From your engineering blog it sounds like you invest heavily in technical quality and have a strong code review process. I also do best with a healthy balance of collaborative time and focused individual work, and I appreciate when remote communication is done thoughtfully. What you have described about your async-first culture sounds like an excellent fit for me.'" },
      { text: "What motivates you at work?", answer: "Authentic motivators that resonate with engineering interviewers: impact — seeing your technical work create measurable value for users, intellectual growth — being challenged by problems that require creativity and force you to learn, craft — the satisfaction of writing elegant well-architected code, and belonging — working alongside talented colleagues you respect. Avoid: mentioning compensation as a primary motivator even if true, generic answers like 'I just love coding' without substance, or motivators completely unrelated to technical work. Strong example: 'Several things genuinely motivate me. First, visible impact: I am energized when I can trace a direct line between code I wrote and a user outcome. When I built a search feature at my current job and then read in user reviews that it was transformative, that was deeply satisfying. Second, intellectual challenge: I do my best work on problems that are hard enough to require creative thinking. I get frustrated in environments where everything is well-understood CRUD work. Third, continuous growth: I want to be meaningfully better as an engineer in a year than I am today, which means I need an environment where there is always something new to learn from either the problems or the people around me. Fourth, ownership: I am most engaged when I own outcomes not just tasks — when the success or failure of a feature is genuinely mine to influence.'" }
    ],
    Medium: [
      { text: "Describe a challenging project you worked on and how you handled it.", answer: "Use the STAR method with emphasis on YOUR specific contribution using 'I' not 'we'. Choose a project that was genuinely complex due to technical difficulty, scale, unclear requirements, or organizational challenges. Quantify the outcome. Example: 'At my previous company we needed to migrate our entire customer-facing application from a monolith to microservices while maintaining 99.9% uptime for our 80,000 daily active users — zero planned downtime was a hard requirement from leadership. My responsibility was designing and implementing the API gateway layer, which was the critical piece enabling gradual traffic migration. I researched approaches and proposed the Strangler Fig pattern — gradually routing traffic to new services while the monolith remained fully operational as a fallback. I designed the migration plan, implemented feature flags for percentage-based traffic routing with instant rollback capability, built automated health checks and circuit breakers, and created a migration runbook that 4 other engineers used. I also organized weekly cross-team syncs since the migration touched teams working on different services. The migration took 7 months and completed without a single unplanned outage. We went from 2-hour deployment cycles to 12-minute CI/CD pipelines and the system reliability improved from 99.5% to 99.95%. The thing I am most proud of is that we did it safely — the rollback capability I built was used three times during the migration, each time transparently to users.'" },
      { text: "Tell me about a time you had a conflict with a coworker. How did you resolve it?", answer: "Show emotional maturity, communication skills, and that you approach conflicts as problems to solve rather than battles to win. Choose a genuine but not extreme example. Structure: briefly describe the disagreement, focus heavily on how you approached resolution, and share the positive outcome. Example: 'About 18 months ago a senior developer on my team and I had a genuine technical disagreement about database schema design for a significant new feature. He advocated for heavy denormalization for read performance. I was concerned about data consistency issues that would create maintenance debt we would regret at scale. We had both stated our positions in a team meeting and it had gotten a bit heated. Rather than continuing the debate in a meeting room, I asked him for a 1-on-1 to discuss it properly. I came to that conversation having prepared a written comparison document showing both approaches with realistic performance projections based on our actual query patterns, data consistency implications with specific examples of where consistency bugs could appear, and estimated maintenance overhead for each approach. Importantly, I also came prepared to genuinely consider I might be wrong. We worked through the document together. We actually ended up with a third hybrid approach that neither of us had considered — partially denormalized with explicit consistency rules enforced in the service layer. We shipped it and 14 months later it is working well with no consistency issues. The experience reinforced for me that technical disagreements resolved with data and genuine openness produce better outcomes than either person would reach alone.'" },
      { text: "Describe a time you failed. What did you learn from it?", answer: "Be genuinely honest — interviewers have strong detectors for deflection or blame-shifting. The goal is to show self-awareness, accountability, and the ability to learn and improve from setbacks. Choose something real with real consequences, but demonstrate specific learnings that you have since applied. Example: 'Two years into my career I was responsible for a database migration that I estimated would take 2 hours based on my testing. It actually ran for 14 hours, taking down a critical reporting feature overnight and requiring my manager to handle frustrated client calls at midnight. The root cause of my failure was that I had tested the migration on a 10,000 row sample dataset and linearly extrapolated the time — but I had not accounted for the fact that our migration required full table locks, and table lock acquisition time scaled non-linearly with table size. Our production table had 4 million rows. I had also not built a tested rollback plan. I owned the mistake completely and did not deflect blame. Three specific things I changed permanently as a result: (1) I now always test database migrations on a production-scale data copy, not a sample, (2) Every migration I run now has a tested and timed rollback script — I literally run the rollback as part of planning, (3) I add a 3x buffer to any estimate involving database operations at scale. I have run 8 significant migrations since then without an incident.'" },
      { text: "How do you prioritize tasks when you have multiple deadlines?", answer: "Demonstrate a systematic approach and emphasize proactive communication as a core part of your process. Interviewers want to see you handle complexity without going silent and missing things. Framework: clarify urgency and importance, communicate early with stakeholders when there are trade-offs to make, break work into deliverable increments to show progress and enable re-prioritization, and protect focus time to execute efficiently. Example: 'When I am juggling multiple priorities I start by mapping each item against two dimensions: its deadline and the downstream impact if it is late — specifically who is blocked or what business outcome is affected. Then I immediately talk to the relevant stakeholders rather than making unilateral priority decisions they do not know about. Last Q3 I had three simultaneous deliverables converging at the same sprint end. Project A was blocking two other engineering teams so it had to come first. For Project B I had a conversation with the PM and showed her that the core value could be delivered in 60% of the original scope — we agreed to ship that and defer the rest to next sprint. For Project C I negotiated a 4-day extension since it was an internal tool with no external commitments. All three shipped, no team was blocked, and stakeholders felt involved in the trade-off decisions rather than surprised by them. The key principle is: communicate early, give stakeholders real information about trade-offs, and never go silent on a commitment without warning.'" },
      { text: "Tell me about a time you had to learn something new quickly.", answer: "Show your actual learning strategy and speed — this is a fundamental competency for engineers since the field changes constantly. Be specific about what you learned, how long it took, and what you delivered as a result. Example: 'When I joined my current team 2 years ago, the entire backend was built with GraphQL — I had exclusively used REST APIs until that point. I had to become productive within 2 weeks because I was assigned to build a new data access feature that required schema changes and resolver logic. My learning approach: Day 1 and 2 I worked through the official GraphQL documentation and built a small side project implementing the patterns. I deliberately built something real rather than just reading. Day 3 I asked our most experienced GraphQL engineer for a 90-minute walkthrough of our specific codebase — I prepared specific questions in advance so the time was focused, not general. Days 4 and 5 I went through our schema and resolver files systematically, writing notes on patterns and design decisions I did not understand. Then I picked three small open GitHub issues as my first tasks — real work, but low-stakes enough to learn. By day 8 I had my first PR merged with positive review feedback. By day 14 I was making schema design decisions and had implemented the originally assigned feature. The principles that made this work: having a real deliverable as motivation keeps learning purposeful, learning from existing production code is faster than documentation alone, and targeted questions to experts beats struggling in isolation.'" }
    ],
    Hard: [
      { text: "Tell me about a time you disagreed with your manager's decision. What did you do?", answer: "This question tests whether you have the professional courage to push back constructively and the maturity to do so through legitimate means while ultimately respecting authority. Wrong answers: always agreed with management (suggests lack of backbone), went around your manager, or were passive-aggressive about the outcome. Strong example: 'My manager decided to skip writing tests for a significant payment processing feature, citing a hard client commitment deadline. I genuinely disagreed — payment code with no tests is a high-risk decision with potential financial impact on users. Rather than just objecting in the team meeting, I asked for a 30-minute dedicated conversation and came prepared with substance. I pulled up three recent production bugs in our untested code from the past quarter, estimated that writing critical integration tests for the three main payment paths would take me approximately 5 hours — less than 10% of the feature work — and proposed a specific scoped compromise: skip unit tests but require integration tests for the core payment flows before shipping. I made clear that I understood the deadline pressure and would implement whatever decision was made, but I wanted to ensure the decision was made with complete information about the risk. My manager agreed to the compromise. We shipped on time. Four months later one of those integration tests caught a regression that would have caused incorrect charges to customers. My manager referenced that outcome specifically in my performance review as an example of good engineering judgment. The lesson I took from it: disagree with data and solutions not just opinions, propose alternatives not just objections, respect authority while advocating clearly, and accept the outcome with full commitment once the decision is made.'" },
      { text: "Describe the most complex problem you have solved professionally.", answer: "Choose a problem with genuine multi-dimensional complexity — technical depth, scale, ambiguity, or organizational coordination. Show systematic thinking, intellectual rigor, and quantified results. Example: 'The most complex problem I have solved was a chronic performance degradation issue where our API response times had grown from an average of 180 milliseconds to over 6 seconds as we scaled from 15,000 to 120,000 users over 18 months. Multiple engineers had looked at this and found no smoking gun. My manager gave me two weeks to find and fix it. I ran a systematic multi-layer investigation rather than guessing. First I added distributed tracing with Jaeger to get visibility into exactly where time was being spent in each request — previously we had no per-service timing data. This revealed that 70% of request time was in database operations. I then enabled query logging and found we were averaging 340 database calls per API request on our most-used endpoints — a severe N+1 query problem caused by ORM misuse in code written 18 months earlier when the dataset was small and the problem was invisible. I also found our cache hit rate was 19% when it should have been above 70% — a cache invalidation bug was clearing the cache too aggressively. And I found 14 missing database indexes on fields we were filtering on. I prioritized by impact: fixed N+1 queries first using eager loading which improved response time by 58%. Added missing indexes for another 24% improvement. Fixed cache invalidation for another 12% improvement. Combined result: average response time went from 6.2 seconds to 165 milliseconds — better than our original baseline. The investigation required database internals knowledge, distributed systems understanding, application profiling skills, and careful communication with stakeholders about progress throughout the two weeks.'" },
      { text: "How do you stay current with industry trends and continuously improve your skills?", answer: "Show genuine specific habits rather than generic platitudes. The most compelling answers are concrete about what you actually read, build, and engage with. Example: 'I have several regular habits that I maintain consistently. For reading: I follow specific authors whose technical judgment I trust — Dan Abramov and Kent C. Dodds for React patterns, Charity Majors and Cindy Sridharan for observability and production engineering, Julia Evans for systems fundamentals. I use RSS feeds rather than social media algorithms to control my information diet. I read approximately 3 to 5 substantial articles per week. For building: I learn by doing, so I maintain active side projects where I deliberately use unfamiliar technology. Currently I am building a CLI tool in Go and an event streaming system with Kafka — both are areas where I want to develop practical expertise. These projects have forced me to understand Go's concurrency model and Kafka's internals in ways that tutorials never would. For community: I attend our local systems programming meetup monthly, which exposes me to problems and perspectives from engineers at very different companies. I find that conversations reveal practical wisdom that published content rarely captures. For structured learning: I allocate roughly one Coursera or Frontend Masters course per quarter for areas where I want systematic depth rather than breadth. Currently working through MIT's Distributed Systems course. At work I deliberately take on at least one task per sprint that stretches me technically — I have found that manufactured stretch is necessary because comfortable work does not create growth.'" }
    ]
  }
};

const getQuestions = (domain, difficulty, count = 5) => {
  const pool = questionsBank[domain]?.[difficulty];
  if (!pool) throw new Error(`No questions for domain: ${domain}, difficulty: ${difficulty}`);
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, Math.min(count, shuffled.length)).map((q, idx) => ({
    text: q.text,
    answer: q.answer,
    order: idx + 1
  }));
};

const findCorrectAnswer = (questionText, domain, difficulty) => {
  const pool = questionsBank[domain]?.[difficulty] || [];
  const found = pool.find(q => q.text === questionText);
  return found ? found.answer : null;
};

const evaluateAnswer = async (question, answer, domain, difficulty, correctAnswer) => {
  // If no correctAnswer passed, look it up from the bank by matching question text
  const resolvedAnswer = correctAnswer || findCorrectAnswer(question, domain, difficulty) || "Please review this topic in your study materials and practice explaining it clearly with examples.";
  const isTimedOut = !answer || answer.trim() === '' || answer === '[Time expired - no answer submitted]';
  if (isTimedOut) {
    return {
      score: 0,
      feedback: "No answer was provided as time expired. Always attempt every question even if incomplete — partial answers show your thought process.",
      strengths: [],
      suggestions: ["Think out loud and start with what you know", "Practice answering under timed conditions daily", "Break complex questions into smaller parts first"],
      correctAnswer: resolvedAnswer
    };
  }
  const wordCount = answer.trim().split(/\s+/).length;
  const hasExamples = /example|instance|for instance|such as|like when|i used|i built|i worked|in my|when i/i.test(answer);
  const hasTechnical = /function|method|array|object|component|api|database|server|class|hook|async|promise|state|props|event|module|query|request|response|algorithm|pattern|render|scope|type|interface/i.test(answer);
  let score = 3;
  if (wordCount >= 20) score += 1;
  if (wordCount >= 50) score += 1;
  if (wordCount >= 80) score += 1;
  if (hasExamples) score += 1;
  if (hasTechnical && domain !== 'HR Questions') score += 1;
  if (wordCount >= 120) score += 1;
  score = Math.min(score, 10);
  const strengths = [];
  if (wordCount >= 40) strengths.push("Provided a detailed response with good depth");
  if (hasExamples) strengths.push("Supported answer with concrete examples");
  if (hasTechnical && domain !== 'HR Questions') strengths.push("Demonstrated relevant technical knowledge");
  if (strengths.length === 0) strengths.push("Attempted the question");
  const suggestions = [];
  if (wordCount < 50) suggestions.push("Elaborate more — aim for at least 60-80 words per answer");
  if (!hasExamples) suggestions.push("Add real examples from your experience or code samples");
  if (!hasTechnical && domain !== 'HR Questions') suggestions.push("Include specific technical terms and concepts relevant to the topic");
  suggestions.push("Structure your answer: define the concept, explain how it works, give an example, mention when to use it");
  return {
    score,
    feedback: score >= 8 ? "Excellent answer! You demonstrated strong understanding with clear, detailed explanation." : score >= 6 ? "Good answer with solid understanding. Adding more specific examples would make it even stronger." : score >= 4 ? "Decent attempt. Try to be more detailed and use specific examples to support your points." : "Your answer needs more depth. Study this topic carefully and practice explaining it out loud.",
    strengths,
    suggestions,
    correctAnswer: resolvedAnswer
  };
};

const generateQuestions = async (domain, difficulty, count = 5) => {
  return getQuestions(domain, difficulty, count);
};

module.exports = { generateQuestions, evaluateAnswer, getQuestions };
